solution_code:
#include <iostream>
#include <vector>
#include <algorithm>

int main()
{
    int n;
    std::cin >> n;
    std::vector<int> v(n);
    for (int i = 0; i < n; ++i)
        std::cin >> v[i];

    std::sort(v.begin(), v.end());

    int m;
    std::cin >> m;
    for (int q = 0; q < m; ++q)
    {
        int target;
        std::cin >> target;
        auto it = std::find(v.begin(), v.end(), target);
        if (it != v.end())
            std::cout << "Found at index " << (it - v.begin()) << '\n';
        else
            std::cout << "Not found\n";
    }

    return 0;
}

